var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음...... 아무도 없네.","JPN":"うーん……誰もいないな。","ENG":"Um... There's nobody here.","TWN":"嗯……怎麼一個人都沒有。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 제일 일찍 온 건가?","JPN":"一番最初に着いたのかな？","ENG":"Did I get here before everyone else?","TWN":"難道我是第一個來的？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"미나 언니!","JPN":"ミナさん！","ENG":"Mina!","TWN":"米娜姐姐！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어? 넌 전에......?","JPN":"あれ？　あなたはこの前の……？","ENG":"Huh? Haven't we met?","TWN":"呃？你是之前……？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네! 하림이에요! 발렌타인 축제 때 만났었죠?","JPN":"はい！　ウサギです！　バレンタイン以来ですね？","ENG":"Yes! It's me, Harim! We met at the Valentine's Day Festival, remember?","TWN":"對！我是夏琳！我們在情人節慶典時見過的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아!","JPN":"そうだね。","ENG":"Oh, right!","TWN":"沒錯！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그 이상한 홍보실 유니폼 입었을 때 말이지.","JPN":"……あの広報室の変なユニフォームを着させられた時だ。","ENG":"I had to put on that ridiculous uniform for the PR team...","TWN":"……我記得當時你穿著奇怪的兔兔？公關部制服。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 나쁜 기억이 떠올라 버렸어......","JPN":"あまり思い出したくないな……","ENG":"Ugh... That suddenly brings back some terrible memories...","TWN":"我突然想起了一些不愉快的記憶……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"기억하실 줄 알았어요! 반가워요, 언니!","JPN":"覚えていてくれて嬉しいです！　お元気でしたか？","ENG":"I knew you'd remember me! It's so good to see you!","TWN":"就知道你會記得！見到你真高興，姐姐！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"본관도 오랜 전우와의 재회에 반가움을 표하는 바이다.","JPN":"本官も久々に戦友と再会できたことを嬉しく思う。","ENG":"I too am pleased about this reunion, soldier.","TWN":"本官也很高興與久別的戰友重逢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"스미스 병장과 함께 초콜릿 괴물들을 격파하던 추억이 다시 떠오르는군.","JPN":"スミス兵長と一緒にチョコレートの化け物を撃破したことを思い出すな。","ENG":"It incites fond memories of slaying those chocolate monsters with Sergeant Smith.","TWN":"這讓我想起與史密斯兵長一起消滅巧克力怪物的事情了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나도 기억나. 그 병정놀이 하던 귀여운 꼬마......","JPN":"覚えてるよ。あの兵隊ごっこをしていた可愛いチビちゃん……","ENG":"I remember you too. You're that adorable kid who used to play soldier...","TWN":"我也記得，沉溺於軍官遊戲的可愛小孩……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"놀이......?","JPN":"ごっこ……？","ENG":"\\"Play?\\"","TWN":"遊戲……？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아니 그러니까......","JPN":"い、いや、だから……","ENG":"Oh, I mean...","TWN":"那、那個，就是……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아! 심판의 방아쇠라고 했었던 것 같은데?","JPN":"そうだ！　審判の引き金と言ってたよね！","ENG":"Oh, right! You go by the Trigger of Judgment, right?","TWN":"對了！好像是叫審判的扳機？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"보, 본관의 이명까지 기억해 주다니! 감격스럽다!","JPN":"ほ、本官のコードネームまで覚えていてくれたとは！　感激だ！","ENG":"Y-you remembered my call sign? I am deeply moved!","TWN":"你竟然還記得本官的暱稱！真是令人感動！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"학교 생활에 고충이 있으면 언제든 본관에게 도움을 요청하도록!","JPN":"学校生活中に困ったことがあれば、いつでも本官に申し出るように！","ENG":"Should you face any tribulations in your campus life, feel free to enlist my aid!","TWN":"如果你在學校裡遇到什麼麻煩，可以隨時來找我幫忙！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 하하......","JPN":"あ……ハハ……","ENG":"Ah, hah hah...","TWN":"啊，哈哈……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 너희들, 설마 이 학교에 다니는 거야?","JPN":"ところであなたたち、この学校に通っているの？","ENG":"You guys go to this school?","TWN":"你們是這裡的學生？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"맞아요! 저희 화이트래빗은 카운터 아카데미의 학생 동아리거든요!","JPN":"はい！　ホワイトラビットはカウンターアカデミー所属のサークルなんです！","ENG":"Yup! White Rabbit is actually a student association here at the Counter Academy!","TWN":"對啊！我們白兔社是制裁者學院的學生社團！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그래서 미나 언니가 우리 학교로 편입했다는 소식도 부사장님한테 들었어요.","JPN":"ミナさんがうちの学校に編入したってことも、副社長から聞いたんです！","ENG":"Your Vice President told us you transferred to our school.","TWN":"米娜姐姐入學的消息也是透過副總那邊知道的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 우리 회사 부사장님이랑 아는 사이야?","JPN":"ん？　副社長とは知り合いなの？","ENG":"Huh? You know my Vice President?","TWN":"嗯？你認識我們公司的副總？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네. 예전부터 동아리 지원금을 후원해 주셨거든요.","JPN":"はい。前からサークルの活動補助金をいただいてるんです。","ENG":"Yes. She's been funding White Rabbit for a while now.","TWN":"是的。她很久以前就開始援助我們社團的資金。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"후원을 부탁하는 편지를 보내자마자 바로 승낙해 주셔서 저희도 깜짝 놀랐어요.","JPN":"後援をお願いするお手紙を送ったらすぐ承諾してくださって、私たちもビックリしました。","ENG":"We were surprised she agreed to support us as soon as we sent her a letter asking for sponsorship.","TWN":"她收到我們發送的請求援助的信件後就馬上同意了呢。當時我們也嚇了一跳。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"탕비실에 음료수도 갖다 놓기 싫어하는 사람이 동아리 지원금을 후원했다니......","JPN":"休憩室にドリンクすら置いてくれない人が学生サークルの後援なんて……","ENG":"That stingy woman barely keeps the break room stocked with drinks... But she funded a student club?","TWN":"連飲料都不想放到茶水間的人竟然贊助了社團支援金…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내일은 해가 서쪽에서 뜬다고 해도 믿겠네.","JPN":"どういう風の吹き回し？","ENG":"Has hell frozen over?","TWN":"明天太陽從西邊出來，我也會信了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쨌든 찾아와 줘서 고마워.","JPN":"まあとにかく、声をかけてくれてありがとう。","ENG":"Anyway, thanks for reaching out to me.","TWN":"總之，你能來我很高興。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 학교 생활에 잘 적응할 수 있게 도와 주러 온 거지?","JPN":"学校生活にはやく慣れるように、手伝いに来てくれたんだね？","ENG":"You're here to help me get settled in, right?","TWN":"你是來幫我適應學校生活的吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사실 너무 오랜만이라 괜찮을지 걱정했는데, 너희들이 도와 준다면 나도 안심이야.","JPN":"実は学校があまりにも久しぶりすぎてちょっと心配だったけど、知り合いがいてホッとしたよ。","ENG":"I was actually worried because it's been so long since I was in school last, but I think I'm in good hands with you guys.","TWN":"其實我因為離開校園太久，還擔心該怎麼適應。如果有你們幫忙的話，我就可以放心了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아! 그 전에 말씀드릴 게 있어요!","JPN":"そうだ！　その前に話があります！","ENG":"Oh! There's something we have to tell you first!","TWN":"啊！我得先傳達一個消息！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"부사장님도 미나 언니가 등교 첫날부터 학교 기물을 파손했다는 걸 알고 계시더라고요.","JPN":"副社長もミナさんが登校初日から学校の器物を破損したことは知っているらしくて。","ENG":"The Vice President is aware that you destroyed school property on your first day here.","TWN":"副總也聽說了米娜姐姐上學第一天就毀掉學校的設備。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"엄~청 딱딱한 말투로 손해 배상은 개인 책임이라고 전해 달라고 하셨어요!","JPN":"すごーく冷たい口調で、損害賠償はすべて個人の責任になると伝えてほしいと言われたんです。","ENG":"She very sternly emphasized you'd have to pay for any damages out of your pocket.","TWN":"她用非~常強硬的語氣讓我告訴你，賠償損失由個人承擔！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그러면 그렇지. 내가 뭘 기대한 거람.","JPN":"……やっぱりな。期待するだけ無駄だった。","ENG":"Yeah, figures. Sounds like hell's still toasty.","TWN":"……我就知道，她完全靠不住。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗! 너무 기운 잃지 마요, 언니!","JPN":"元気出してくださいね！","ENG":"Oh! There's no need to look so down!","TWN":"哎，你也別太沮喪，姐姐！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그렇다. 전우의 학교 생활은 본관이 전력으로 지원하겠다.","JPN":"そうだ。戦友の学校生活は本官が全力で支援する。","ENG":"Indeed. I will do everything in my power to ensure the success of your academic endeavors.","TWN":"不錯。我會全力支持戰友的學校生活。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그러니 궁금한 건 뭐든 물어 보도록.","JPN":"だから、わからないことは何でも聞きたまえ。","ENG":"So feel free to ask me any questions.","TWN":"所以，有任何疑問，你都可以提問。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하아...... 그래, 고마워.","JPN":"ハハ……ありがとうね。","ENG":"*Sigh* Oh well. Thanks guys.","TWN":"哈啊……好啊，謝謝。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 너희들도 오늘 다이브 실전 훈련에 참가하는 거야?","JPN":"ところで、あなたたちも今日のダイブ実戦訓練に参加するの？","ENG":"Are you going on Dive training today too?","TWN":"可是你們也要參加今天的躍入實戰訓練嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아, 저희는 아니에요. 다이브 훈련은 고등부만 참가하거든요.","JPN":"あ、私たちは違います。ダイブ訓練は高等部だけ参加できるんです。","ENG":"Oh, not us. Dive training is only for high schoolers.","TWN":"哦，我們不是。只有高等部參加躍入訓練。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래? 그럼 자세한 얘기는 다녀와서 해야겠네.","JPN":"そうなの？　それじゃあ、おしゃべりの続きは帰ってきてからにしなきゃね。","ENG":"Is that right? Then I guess we'll have to talk more after I come back.","TWN":"這樣？那只能等我回來後再聊了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"음...... 네, 그렇긴 한데요......","JPN":"うーん……そうですね。でも……","ENG":"Um... About that...","TWN":"嗯……其實我有事要說……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜? 무슨 걱정이라도 있어?","JPN":"どうしたの？　何か気になることでも？","ENG":"What's wrong? Something bothering you?","TWN":"怎麼了？你有什麼擔心的事情嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"우리 팀의 호진 언니 대원이 어제 옥상 난간에 매달린 고양이를 구출하려다 발이 삐었기 때문이다.","JPN":"我がチームのマユミ隊員が昨日、屋上の屋根で身動きが取れなくなった猫を救出する際に足を捻ったのだ。","ENG":"Our teammate, Operative Hojin, sprained her ankle while trying to rescue a kitten from a tree yesterday.","TWN":"我們隊的鎬眞姐姐昨天為了救出高台欄杆上的小貓而扭到腳了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그것 때문에 호진 언니는 고등부인데도 오늘 훈련에서 빠지게 됐어요.","JPN":"そのせいでマユミさんは高等部なのに今日の訓練に参加できなくなったんです。","ENG":"So she had to drop out of the Dive although she's in high school.","TWN":"鎬真姐姐就是高等部的學生，但因為受傷沒辦法參加今天的訓練。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어...... 많이 다친 거야?","JPN":"えーと……大怪我してしまったのかな？","ENG":"Oh... Did she hurt herself badly?","TWN":"呃……受傷嚴重嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"아니. 양호 교사는 며칠 쉬면 금방 낫는다고 보고했다.","JPN":"いや、保健室の教師から数日休めばすぐ治るという報告を受けた。","ENG":"Negative. The nurse said she'll fully recover with a few days' rest.","TWN":"不重，保健室的阿姨說是休息幾天就能痊癒。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그런데 호진 언니가 평소에 운이 엄청 좋거든요.","JPN":"でも、マユミさんって普段とても運がいい人なんです。","ENG":"The thing is, Hojin's usually really lucky.","TWN":"但是鎬眞姐姐平常運氣都非常好的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"학교 매점에서 제일 인기 많은 핫도그 빵도 호진 언니가 사러 갈 땐 항상 하나씩 남아 있을 정도로요.","JPN":"学校の売店で一番人気のコッペパンも、マユミさんが買いに行く時は必ず1個残っているくらいなんです。","ENG":"She always manages to score the last hot dog at the snack bar before they sell out.","TWN":"學校合作社最具人氣的熱麵包，每次鎬真姐姐去買都會買到。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"본관도 자주 부탁하고는 하지. ","JPN":"だから本官もよく頼んでいる。","ENG":"I am much obliged to her for that. ","TWN":"所以我也經常拜託她幫我買。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"덕분에 다른 학생들과 교전하지 않고 성공리에 보급 중이다.","JPN":"おかげで他の生徒と交戦せずに、見事に補給に成功している。","ENG":"Thanks to her, I've secured a steady supply of victuals without resorting to kinetic disputes with other students.","TWN":"平常與其他學生的戰鬥都得益於她的幸運成功晉級。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그거 참 저렴한 행운이네......","JPN":"そ、それはお安い幸運だね……","ENG":"I can think of a better use for that good luck...","TWN":"那可真是廉價的幸運……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그래서 호진 언니가 빠진다고 하니까...... 혹시 위험한 일이 일어날까 봐 걱정돼요.","JPN":"今回マユミさんが急に参加できなくなったから……もしかしてよくないことが起きるんじゃないかと心配なんです。","ENG":"So now that Hojin's not going on the Dive... I'm worried something terrible might happen during the training mission.","TWN":"所以這次鎬真姐姐缺席……我擔心會發生危險的事情。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고마워. 다른 사람이 그렇게 걱정해 주는 건 오랜만인 것 같네.","JPN":"ありがとう。他の人がそんなに心配してくれるのは久しぶりな気がする。","ENG":"Thanks. It's been a while since anyone worried for me so sincerely.","TWN":"謝謝你，好久沒有人這樣關心我了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래도 너무 신경 쓸 건 없어. 이면세계는 원래 위험한 곳이잖아.","JPN":"でもあまり気にすることないよ。裏世界は元々危険な場所だから。","ENG":"But don't let it bother you too much. The Counterside is already dangerous as it is.","TWN":"不過也不用太擔心，異界本來就很危險。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"으음......","JPN":"うーん……","ENG":"But...","TWN":"唔……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"전우의 실력은 알고 있지만 긴장해라. 전장에서 방심은 죽음을 부른다.","JPN":"戦友の実力は承知しているが、緊張の糸を切らさないように。戦場での油断は死を招く。","ENG":"We're aware of your capabilities, but proceed with due caution. For death is always around the bend on the field.","TWN":"我雖然知道戰友的實力，但在戰場上粗心大意就離死亡不遠了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"맞아요! 혹시 모르니까 조심 또 조심하시기예요!","JPN":"そうです！　念のため用心を！","ENG":"That's right! Please be extra careful out there, just in case!","TWN":"說的對！為了以防萬一，你還是小心為上！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 알았어. 조심할게.","JPN":"うん、わかった。気を付けるね。","ENG":"Yeah, I got it. I'll be careful.","TWN":"嗯，知道了。我會小心的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나야! 아직 안 늦었지?!","JPN":"ミナちゃん！　まだ間に合うよね！？","ENG":"Mina! They haven't left without us, have they?","TWN":"米娜！我沒遲到吧？！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"레이 선배가 자꾸 늑장 부리는 바람에 나까지 지각이라니까!","JPN":"レイ先輩がダラダラするから、私まで遅刻しちゃったの！","ENG":"Ray dragged his feet so much that I ended up being late too!","TWN":"都是雷伊前輩太拖拖拉拉了，害我也差點遲到！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"하, 하지만 오늘은 정말 컨디션이 안 좋은 걸......","JPN":"で、でも今日は本当に調子が悪いんだ……","ENG":"B-but I'm really not feeling very well today...","TWN":"其、其實我今天的身體狀態有些不好……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"꾀병은 그만둬요, 선배!","JPN":"仮病はやめてください、先輩！","ENG":"Stop playing sick!","TWN":"別裝病了，前輩！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"좋든 싫든 이제부터 우리는 살아도 한 몸! 죽어도 한 몸!","JPN":"嫌だとしても、私たちは同じ船に乗った仲間！　死ぬ時も一緒！","ENG":"Whether you like it or not, we live as one! And we die as one!","TWN":"現在開始不管你高不高興，我們要死要活都是一體了！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자꾸 그러시면 선배한테 연필이 사라지는 마술을 보여 줄 테니까요!","JPN":"また弱音を吐いたら先輩を鉛筆が消える手品の実験台にしますから！","ENG":"If you keep whining, I'll show you that magic trick with the pencil!","TWN":"如果你再這樣的話，我就馬上表演鉛筆消失的魔術！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"히이익!","JPN":"ひいいっ！","ENG":"Eeep!","TWN":"（大驚）咿！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"참, 이럴 때가 아니지!","JPN":"そうだ、こうしてる場合じゃない！","ENG":"Oops, we shouldn't be lounging around like this right now!","TWN":"哎，現在不是說這些的時候！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나야! 어서 가자! 이러다 함선이 출발하겠어!","JPN":"ミナちゃん、急ごう！　艦船が出発しちゃうよ！","ENG":"Mina! Hurry! The ship's going to leave us behind at this rate!","TWN":"米娜！快走吧！再耽擱下去艦船就出發了！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알겠어. 금방 갈게.","JPN":"わかった。今行くよ。","ENG":"Okay. I'll be right there.","TWN":"知道了，馬上就來。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 다녀와서 보자. 비싼 건 어렵겠지만 다음에 볼 땐 내가 간식이라도 사 줄게.","JPN":"それじゃ、またね。高いのは無理だけど、今度ジュースでも奢ってあげるね。","ENG":"Well, I'll see you guys when I get back. I'll treat you to some snacks next time we meet... although I can't afford anything fancy.","TWN":"那等我回來再說吧。下次見面的時候買零食給你們，當然貴的不行。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네! 기다리고 있을게요!","JPN":"はい！　ありがとうございます！","ENG":"Okay! We'll be waiting!","TWN":"好的！我會等你！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"무사 귀환을 기원하겠다, 전우여!","JPN":"無事帰還を祈る、戦友よ！","ENG":"I wish you a safe and speedy return, sister-in-arms!","TWN":"希望你安全歸來，我的戰友！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};